   337|function buildOwnerDeveloperConnectionString(): string {
   338|  const explicitConnectionString = readBackendEnv('SUPABASE_OWNER_DATABASE_URL')
   339|    || readBackendEnv('SUPABASE_DB_URL')
   340|    || readBackendEnv('DATABASE_URL')
   341|    || readBackendEnv('POSTGRES_URL');
   342|  if (explicitConnectionString) {
   343|    return explicitConnectionString;
   344|  }
   345|  const supabaseUrl = readBackendEnv('EXPO_PUBLIC_SUPABASE_URL');
   346|  const password = readBackendEnv('SUPABASE_DB_PASSWORD');
   347|  if (!supabaseUrl || !password) {
   348|    throw new Error('Supabase database connection is not configured server-side.');
   349|  }
   350|  const projectRef = new URL(supabaseUrl).hostname.split('.')[0] ?? '';
   351|  if (!projectRef) {
   352|    throw new Error('Unable to derive Supabase project ref server-side.');
   353|  }
   354|  return `postgres://postgres:${encodeURIComponent(password)}@db.${projectRef}.supabase.co:5432/postgres?sslmode=require&application_name=ivx_owner_developer_tools`;
