    30|export type IVXDeploymentState = 'READY' | 'RUNNING' | 'BLOCKED' | 'VERIFIED';
    31|
    32|/** Evidence required to claim VERIFIED. Every field must be present and
    33| *  non-null — no partial proof is allowed to claim VERIFIED. */
    34|export type IVXDeploymentVerifiedEvidence = {
